func (c *Client) RecursiveDocumentQuery(documentPath string) Query {
	// make a query with parent set to this document, then collection id unset.
	docRef := c.Doc(documentPath)
	q := Query{c: c}.Select(DocumentID)

	// Collection id should be unset.
	q.collectionID = ""

	// Parent path should be configured to this document
	q.parentPath = docRef.Path
	q.path = q.parentPath

	q.allDescendants = true

	return q
}

